let input = {};
try { input = $input.item.json; } catch(e) {}
try { if (!input || !input.businessName) input = $json; } catch(e) {}

const projectType = input.projectType || 'landing_page';
const businessName = input.businessName || 'My Business';
const languages = input.languages || ['hu'];
const description = input.description || '';
const designStyle = input.designStyle || 'modern';
const aiModel = input.aiModel || 'deepseek-chat';
const customPrompt = input.customPrompt || '';
const notifyEmail = input.notifyEmail || '';
const colors = input.colors || { primary: '#6366f1', secondary: '#8b5cf6', accent: '#f59e0b', headerBg: '#ffffff', footerBg: '#1f2937' };
const headerLogo = input.headerLogo || null;
const footerLogo = input.footerLogo || null;
const header = input.header || [];
const footer = input.footer || [];
const hero = input.hero || { enabled: true, height: 600 };

let pages = input.pages || [];
if (pages.length > 0 && typeof pages[0] === 'string') {
  pages = pages.map(p => ({ name: p, slug: p.toLowerCase(), description: '', subpages: [] }));
}

return { businessName, projectType, languages, description, designStyle, aiModel, customPrompt, notifyEmail, colors, headerLogo, footerLogo, header, hero, footer, pages };

const data = $input.all()[0].json;
const lang = data.languages[0] || 'hu';

const pageList = data.pages.map(p => {
  let line = p.name + ' (' + p.slug + ')';
  if (p.description) line += ': ' + p.description;
  if (p.subpages && p.subpages.length > 0) line += ' [Aloldalak: ' + p.subpages.map(sp => sp.name + '(' + sp.slug + ')' + (sp.description ? ': ' + sp.description : '')).join(', ') + ']';
  return line;
}).join('
');

const heroInfo = data.hero && data.hero.enabled ? `Hero: YES, height: ${data.hero.height}px.` : 'Hero: NO.';
const headerInfo = data.header && data.header.length > 0 ? 'Header: ' + data.header.join(', ') : 'Header: standard';
const footerInfo = data.footer && data.footer.length > 0 ? 'Footer: ' + data.footer.join(', ') : 'Footer: standard';
const anyAi = [data.colors.primary,data.colors.secondary,data.colors.accent,data.colors.headerBg,data.colors.footerBg].filter(c => c === 'ai').length > 0;

const base = `Project: ${data.businessName}
Type: ${data.projectType}
Language: ${lang}
Description: ${data.description}
Design: ${data.designStyle}
Colors - Primary: ${data.colors.primary}, Secondary: ${data.colors.secondary}, Accent: ${data.colors.accent}, Header BG: ${data.colors.headerBg}, Footer BG: ${data.colors.footerBg}
${anyAi ? 'Colors marked "ai": choose matching hex colors.
' : ''}${headerInfo}
${footerInfo}
${heroInfo}

Pages:
${pageList}

Output JSON:
{
  "pages": { "[slug]": { "title": "...", "content": { "hero": {...}, "sections": [...] }, "meta": {...}, "subpages": {...} } },
  "config": { "system": {...}, "theme": { "colors": {...} }, "header": {...}, "footer": {...}, "plugins": ["form","email","seo","sitemap"] },
  "admin_structure": {...}
}

Professional, SEO-optimized. List Gravity CMS plugins.`;

const prompt = data.customPrompt ? base + '

ADDITIONAL INSTRUCTIONS: ' + data.customPrompt : base;

return { prompt, aiModel: data.aiModel, languages: data.languages, businessName: data.businessName, notifyEmail: data.notifyEmail };

const fs = require('fs');
const path = require('path');
const response = $input.all()[0].json;

let content;
try {
  const aiResponse = response.choices[0].message.content;
  let jsonStr = aiResponse;
  if (jsonStr.includes('```json')) jsonStr = jsonStr.split('```json')[1].split('```')[0].trim();
  else if (jsonStr.includes('```')) jsonStr = jsonStr.split('```')[1].split('```')[0].trim();
  content = JSON.parse(jsonStr);
} catch (e) {
  content = { error: "Parse failed", raw: response.choices[0].message.content };
}

const bizName = ($items('Bemenet feldolgozása (Code)').$node['Bemenet feldolgozása (Code)'].json || {}).businessName || 'unknown';
const safeName = bizName.toLowerCase().replace(/[^a-z0-9]/g, '_').substring(0, 30);
const ts = new Date().toISOString().replace(/[:.]/g, '-');

// ---- JSON mentés ----
const outputDir = '/home/node/output';
const jsonFile = path.join(outputDir, safeName + '_' + ts + '.json');
try { if (!fs.existsSync(outputDir)) fs.mkdirSync(outputDir, { recursive: true }); fs.writeFileSync(jsonFile, JSON.stringify(content, null, 2), 'utf8'); } catch (err) {}

// ---- Verziókövetés ----
const versionsDir = path.join(outputDir, 'versions');
try { if (!fs.existsSync(versionsDir)) fs.mkdirSync(versionsDir, { recursive: true }); fs.writeFileSync(path.join(versionsDir, safeName + '_' + ts + '.json'), JSON.stringify(content, null, 2), 'utf8'); } catch (err) {}

// ---- Gravity CMS deploy ----
if (content.pages) {
  const gravPagesDir = '/home/node/gravity-pages';
  try {
    if (!fs.existsSync(gravPagesDir)) fs.mkdirSync(gravPagesDir, { recursive: true });
    Object.keys(content.pages).forEach(slug => {
      const page = content.pages[slug];
      const pageDir = path.join(gravPagesDir, '01.' + safeName);
      if (!fs.existsSync(pageDir)) fs.mkdirSync(pageDir, { recursive: true });
      const mdName = slug === 'home' ? 'default.md' : slug + '.md';
      let md = '---\ntitle: "' + (page.title || slug) + '"\n';
      if (page.meta) md += 'metadata:\n  description: "' + (page.meta.description || '') + '"\n';
      md += 'visible: true\n---\n\n';
      if (page.content && page.content.hero) { md += '# ' + (page.content.hero.title || '') + '\n\n' + (page.content.hero.subtitle || '') + '\n\n'; }
      if (page.content && page.content.sections) { page.content.sections.forEach(sec => { md += '## ' + (sec.title || '') + '\n\n' + (sec.content || '') + '\n\n'; }); }
      fs.writeFileSync(path.join(pageDir, mdName), md, 'utf8');
    });
  } catch (err) {}
}

// ---- Plugin info ----
let plugins = [];
if (content.config && content.config.plugins) plugins = content.config.plugins;

return { generated: content, saved_to: jsonFile, gravity_deployed: !!content.pages, plugins: plugins, timestamp: new Date().toISOString(), model: response.model || 'deepseek-chat', usage: response.usage || {} };
